66	    EventBridgeService(StorageBackend<String, EventBus> busStore,
67	                       StorageBackend<String, Rule> ruleStore,
68	                       StorageBackend<String, List<Target>> targetStore,
69	                       RegionResolver regionResolver,
70	                       LambdaService lambdaService,
71	                       SqsService sqsService,
