    @Test
    void matchesPatternByResources() {
        Map<String, Object> event = Map.of(
                "Source", "my.app",
                "DetailType", "OrderCreated",
                "Resources", List.of("arn:aws:ec2:us-east-1:123456789012:instance/i-1234567890abcdef0")
        );

        assertTrue(service.matchesPattern(event,
                "{\"resources\":[\"arn:aws:ec2:us-east-1:123456789012:instance/i-1234567890abcdef0\"]}"));
        assertFalse(service.matchesPattern(event,
                "{\"resources\":[\"arn:aws:ec2:us-east-1:123456789012:instance/i-00000000000000000\"]}"));
    }

    @Test
    void matchesPatternByResourcesAndSource() {
        Map<String, Object> event = Map.of(
                "Source", "my.app",
                "DetailType", "OrderCreated",
                "Resources", List.of("arn:aws:ec2:us-east-1:123456789012:instance/i-1234567890abcdef0")
        );

        assertTrue(service.matchesPattern(event,
                "{\"source\":[\"my.app\"],\"resources\":[\"arn:aws:ec2:us-east-1:123456789012:instance/i-1234567890abcdef0\"]}"));
        assertFalse(service.matchesPattern(event,
                "{\"source\":[\"my.app\"],\"resources\":[\"arn:aws:ec2:us-east-1:123456789012:instance/i-00000000000000000\"]}"));
    }

    @Test
    void matchesPatternResourcesOnlyOnList() {
        // Verify that an event with Resources as list is handled properly
        Map<String, Object> event = new java.util.HashMap<>();
        event.put("Source", "my.app");
        event.put("Resources", List.of("res-1", "res-2"));

        assertTrue(service.matchesPattern(event, "{\"resources\":[\"res-1\"]}"));
        assertTrue(service.matchesPattern(event, "{\"resources\":[\"res-2\"]}"));
        assertFalse(service.matchesPattern(event, "{\"resources\":[\"res-3\"]}"));
    }
}

