351	    // ──────────────────────────── Pattern Matching ────────────────────────────
352	
353	    boolean matchesPattern(Map<String, Object> event, String eventPattern) {
354	        if (eventPattern == null || eventPattern.isBlank()) {
355	            return true;
356	        }
357	        try {
358	            JsonNode pattern = objectMapper.readTree(eventPattern);
359	            JsonNode sourceField = pattern.get("source");
360	            if (sourceField != null && sourceField.isArray()) {
361	                String eventSource = (String) event.get("Source");
362	                if (!matchesArrayField(sourceField, eventSource)) {
363	                    return false;
364	                }
365	            }
366	            JsonNode detailTypeField = pattern.get("detail-type");
367	            if (detailTypeField != null && detailTypeField.isArray()) {
368	                String eventDetailType = (String) event.get("DetailType");
369	                if (!matchesArrayField(detailTypeField, eventDetailType)) {
370	                    return false;
371	                }
372	            }
373	            JsonNode resourcesField = pattern.get("resources");
374	            if (resourcesField != null && resourcesField.isArray()) {
375	                Object eventResources = event.get("Resources");
376	                if (!matchesResourcesField(resourcesField, eventResources)) {
377	                    return false;
378	                }
379	            }
380	            JsonNode detailPattern = pattern.get("detail");
381	            if (detailPattern != null && detailPattern.isObject()) {
382	                Object eventDetail = event.get("Detail");
383	                String detailStr = eventDetail instanceof String s ? s : null;
384	                if (detailStr == null) {
385	                    return false;
386	                }
387	                JsonNode detailNode = objectMapper.readTree(detailStr);
388	                var fields = detailPattern.fields();
389	                while (fields.hasNext()) {
390	                    var field = fields.next();
391	                    JsonNode expected = field.getValue();
392	                    JsonNode actual = detailNode.get(field.getKey());
393	                    String actualStr = actual != null ? actual.asText(null) : null;
394	                    if (expected.isArray() && !matchesArrayField(expected, actualStr)) {
395	                        return false;
396	                    }
397	                }
398	            }
399	            return true;
400	        } catch (Exception e) {
401	            LOG.warnv("Failed to parse event pattern: {0}", e.getMessage());
402	            return false;
403	        }
404	    }
405	
406	    private boolean matchesArrayField(JsonNode arrayNode, String value) {
407	        if (value == null) return false;
408	        for (JsonNode element : arrayNode) {
409	            if (value.equals(element.asText())) {
410	                return true;
411	            }
412	        }
413	        return false;
414	    }
415	
416	    private boolean matchesResourcesField(JsonNode arrayNode, Object resources) {
417	        if (resources == null) return false;
418	        List<?> resourceList;
419	        if (resources instanceof List<?> list) {
420	            resourceList = list;
421	        } else {
422	            return false;
423	        }
424	        for (Object resource : resourceList) {
425	            String resourceStr = resource != null ? resource.toString() : null;
426	            for (JsonNode element : arrayNode) {
427	                if (resourceStr != null && resourceStr.equals(element.asText())) {
428	                    return true;
429	                }
430	            }
431	        }
432	        return false;
433	    }
