437	    private void invokeTarget(Target target, String eventJson, String region) {
438	        String arn = target.getArn();
439	        String payload = target.getInput() != null ? target.getInput() : eventJson;
440	        try {
441	            if (arn.contains(":lambda:") || arn.contains(":function:")) {
442	                String fnName = arn.substring(arn.lastIndexOf(':') + 1);
443	                String fnRegion = extractRegionFromArn(arn, region);
444	                lambdaService.invoke(fnRegion, fnName, payload.getBytes(), InvocationType.Event);
445	                LOG.debugv("EventBridge delivered to Lambda: {0}", arn);
446	            } else if (arn.contains(":sqs:")) {
447	                String queueUrl = sqsArnToUrl(arn);
448	                sqsService.sendMessage(queueUrl, payload, 0);
449	                LOG.debugv("EventBridge delivered to SQS: {0}", arn);
450	            } else if (arn.contains(":sns:")) {
451	                String topicRegion = extractRegionFromArn(arn, region);
452	                snsService.publish(arn, null, payload, "EventBridge", topicRegion);
453	                LOG.debugv("EventBridge delivered to SNS: {0}", arn);
454	            } else {
455	                LOG.warnv("EventBridge: unsupported target ARN type: {0}", arn);
456	            }
457	        } catch (Exception e) {
458	            LOG.warnv("EventBridge failed to deliver to target {0}: {1}", arn, e.getMessage());
459	        }
460	    }
