462	    private String buildEventEnvelope(Map<String, Object> entry, String busName, String eventId) {
463	        try {
464	            String source = (String) entry.getOrDefault("Source", "");
465	            String detailType = (String) entry.getOrDefault("DetailType", "");
466	            String detail = (String) entry.getOrDefault("Detail", "{}");
467	            ObjectNode node = objectMapper.createObjectNode();
468	            node.put("version", "0");
469	            node.put("id", eventId);
470	            node.put("source", source);
471	            node.put("detail-type", detailType);
472	            node.put("account", regionResolver.getAccountId());
473	            node.put("time", Instant.now().toString());
474	            node.put("region", regionResolver.getDefaultRegion());
475	            // Forward the Resources array from the event entry
476	            Object resourcesObj = entry.get("Resources");
477	            if (resourcesObj instanceof List<?> resourcesList) {
478	                var resourcesArray = node.putArray("resources");
479	                for (Object resource : resourcesList) {
480	                    if (resource != null) {
481	                        resourcesArray.add(resource.toString());
482	                    }
483	                }
484	            } else {
485	                node.putArray("resources");
486	            }
487	            node.set("detail", objectMapper.readTree(detail));
488	            node.put("event-bus-name", busName);
489	            return objectMapper.writeValueAsString(node);
490	        } catch (Exception e) {
491	            return "{}";
492	        }
493	    }
